from __future__ import annotations

import argparse
import datetime as dt
import os
import subprocess
import sys
from pathlib import Path
from typing import Iterable

DEFAULT_ROOT = Path.home() / ".zeroclaw"
DEFAULT_STATE_DIR = Path.home() / ".local" / "state" / "hermes-zeroclaw-backup"
DEFAULT_LOG_FILE = DEFAULT_STATE_DIR / "cron.log"
LOCK_FILE = DEFAULT_STATE_DIR / "git-auto-backup.lock"


class GitCommandError(RuntimeError):
    pass


def run_git(repo: Path, args: list[str], check: bool = True) -> str:
    result = subprocess.run(
        ["git", *args],
        cwd=repo,
        text=True,
        capture_output=True,
    )
    if check and result.returncode != 0:
        raise GitCommandError(
            f"git {' '.join(args)} failed in {repo}: {result.stderr.strip() or result.stdout.strip()}"
        )
    return result.stdout.strip()


def discover_repos(root: Path) -> list[Path]:
    repos: list[Path] = []
    for current_root, dirnames, filenames in os.walk(root):
        current = Path(current_root)
        if ".git" in dirnames or ".git" in filenames:
            repos.append(current)
            dirnames[:] = [d for d in dirnames if d != ".git"]
    return sorted(set(repos), key=lambda p: (len(p.parts), str(p)))


def safe_branch(repo: Path) -> str:
    branch = run_git(repo, ["branch", "--show-current"])
    return branch or "detached-head"


def summarize_changes(repo: Path) -> tuple[str, list[str]]:
    status_lines = [line for line in run_git(repo, ["diff", "--cached", "--name-status"]).splitlines() if line.strip()]
    numstat_lines = [line for line in run_git(repo, ["diff", "--cached", "--numstat"]).splitlines() if line.strip()]

    files: list[str] = []
    additions = 0
    deletions = 0
    change_kinds: set[str] = set()

    for line in status_lines:
        parts = line.split("\t")
        if not parts:
            continue
        kind = parts[0]
        if kind:
            change_kinds.add(kind[0])
        files.append(parts[-1])

    for line in numstat_lines:
        parts = line.split("\t")
        if len(parts) < 3:
            continue
        add_raw, del_raw = parts[0], parts[1]
        if add_raw.isdigit():
            additions += int(add_raw)
        if del_raw.isdigit():
            deletions += int(del_raw)

    repo_name = repo.name
    branch = safe_branch(repo)
    if "A" in change_kinds and change_kinds <= {"A"}:
        verb = "add"
    elif change_kinds <= {"D"}:
        verb = "remove"
    elif change_kinds <= {"R"}:
        verb = "rename"
    elif change_kinds & {"M", "R"}:
        verb = "update"
    else:
        verb = "sync"

    preview = ", ".join(files[:3])
    if len(files) > 3:
        preview += f", +{len(files) - 3} more"

    timestamp = dt.datetime.now(dt.timezone.utc).strftime("%Y-%m-%d %H:%M UTC")
    message = (
        f"chore(autobackup): {verb} {repo_name}/{branch} ({len(files)} files, +{additions}/-{deletions})"
    )
    if preview:
        message += f" [{preview}]"
    message += f" @ {timestamp}"
    return message, files


def ensure_identity(repo: Path) -> None:
    for key, fallback in [
        ("user.name", "Orbiracle"),
        ("user.email", "orbiracle@localhost"),
    ]:
        value = run_git(repo, ["config", "--get", key], check=False)
        if not value:
            run_git(repo, ["config", key, fallback])


def stage_commit_push(repo: Path) -> str | None:
    ensure_identity(repo)
    run_git(repo, ["add", "-A"])
    diff_exit = subprocess.run(
        ["git", "diff", "--cached", "--quiet"], cwd=repo, text=True, capture_output=True
    ).returncode
    if diff_exit == 0:
        return None
    if diff_exit not in (0, 1):
        raise GitCommandError(f"git diff --cached --quiet failed in {repo}")

    message, files = summarize_changes(repo)
    if not files:
        return None

    run_git(repo, ["commit", "-m", message])

    upstream = run_git(repo, ["rev-parse", "--abbrev-ref", "--symbolic-full-name", "@{u}"], check=False)
    branch = safe_branch(repo)
    if upstream:
        run_git(repo, ["push"])
    else:
        remotes = run_git(repo, ["remote"]).splitlines()
        remote = "origin" if "origin" in remotes else (remotes[0] if remotes else "")
        if not remote:
            raise GitCommandError(f"No git remote configured for {repo}")
        run_git(repo, ["push", "-u", remote, branch])
    return message


def main() -> int:
    parser = argparse.ArgumentParser()
    parser.add_argument("--root", default=str(DEFAULT_ROOT))
    args = parser.parse_args()

    root = Path(args.root).expanduser().resolve()
    DEFAULT_STATE_DIR.mkdir(parents=True, exist_ok=True)
    if not root.exists():
        print(f"[{dt.datetime.now().isoformat()}] root missing: {root}")
        return 1

    try:
        import fcntl  # type: ignore
    except ImportError as exc:
        raise RuntimeError("fcntl required on this platform") from exc

    with open(LOCK_FILE, "w") as lock_handle:
        try:
            fcntl.flock(lock_handle.fileno(), fcntl.LOCK_EX | fcntl.LOCK_NB)
        except BlockingIOError:
            print(f"[{dt.datetime.now().isoformat()}] skipped: lock held")
            return 0

        repos = discover_repos(root)
        if not repos:
            print(f"[{dt.datetime.now().isoformat()}] no git repos under {root}")
            return 0

        committed: list[tuple[Path, str]] = []
        skipped: list[Path] = []

        for repo in repos:
            try:
                message = stage_commit_push(repo)
            except Exception as exc:  # noqa: BLE001
                print(f"[{dt.datetime.now().isoformat()}] ERROR {repo}: {exc}", file=sys.stderr)
                return 1
            if message:
                committed.append((repo, message))
            else:
                skipped.append(repo)

        now = dt.datetime.now().isoformat()
        if committed:
            print(f"[{now}] committed {len(committed)} repo(s)")
            for repo, message in committed:
                print(f"  - {repo}: {message}")
        else:
            print(f"[{now}] no changes in {len(skipped)} repo(s)")
        return 0


if __name__ == "__main__":
    raise SystemExit(main())
