def summarize_worktree(repo: Path) -> tuple[str, list[str]]:
    porcelain_lines = [line for line in run_git(repo, ["status", "--porcelain"]).splitlines() if line.strip()]
    files: list[str] = []
    change_kinds: set[str] = set()

    for line in porcelain_lines:
        status = line[:2]
        path_part = line[3:]
        if " -> " in path_part:
            path_part = path_part.split(" -> ", 1)[1]
        if path_part:
            files.append(path_part)
        for marker in status:
            if marker not in {" ", "?"}:
                change_kinds.add(marker)
            elif marker == "?":
                change_kinds.add("A")

    return _compose_message(repo, files, 0, 0, change_kinds)
